import React, { useState, useEffect } from 'react';
import axios from 'axios';

const WeatherAlert = () => {
  const [weatherData, setWeatherData] = useState(null);
  const [alert, setAlert] = useState(null);
  const [city, setCity] = useState('Colombo'); // Default city
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchWeather = async () => {
      setError(null);
      try {
        // No API key in the URL anymore
        const response = await axios.get(
          `http://localhost:5000/api/weather/alerts?city=${encodeURIComponent(city)}`
        );
        setWeatherData(response.data);
        setAlert(response.data.alert || null);
      } catch (err) {
        console.error('Error fetching weather data:', err);
        setError('Failed to fetch weather data. Please try again.');
        setWeatherData(null);
        setAlert(null);
      }
    };

    if (city && city.trim()) {
      fetchWeather();
    }
  }, [city]);

  return (
    <div className="weather-alert-container">
      <h2>Weather Alerts for {city || '—'}</h2>
      <input
        type="text"
        value={city}
        onChange={(e) => setCity(e.target.value)}
        placeholder="Enter city"
      />
      <div>
        {error && <p style={{ color: 'red' }}>{error}</p>}

        {alert ? (
          <div className="alert">
            <strong>Weather Alert:</strong> {alert}
          </div>
        ) : (
          <p>No alerts at the moment.</p>
        )}

        {weatherData && !alert && (
          <p>Temperature: {weatherData.temp}°C</p>
        )}
      </div>
    </div>
  );
};

export default WeatherAlert;
